// INPUT
const title = $json.title || "";
const meta = $json.meta || "";
const h1 = $json.h1 || "";
const contentLength = $json.contentLength || 0;
let links = $json.links || [];

// =======================
// 1. CLEAN LINKS
// =======================
links = links.filter(link => link && typeof link === "string");
links = [...new Set(links)];

// =======================
// 2. LINK CATEGORIZATION
// =======================
const internalLinks = links.filter(link => link.startsWith("/"));
const externalLinks = links.filter(link => link.startsWith("http"));
const anchorLinks = links.filter(link => link.startsWith("#"));
const mailLinks = links.filter(link => link.startsWith("mailto"));

// =======================
// 3. KEYWORD LOGIC
// =======================
// (Replace with dynamic keyword later)
const keyword = "data analytics";
const keywordLower = keyword.toLowerCase();

const keywordInTitle = title.toLowerCase().includes(keywordLower);
const keywordInMeta = meta.toLowerCase().includes(keywordLower);
const keywordInH1 = h1.toLowerCase().includes(keywordLower);

const keywordScore = [
  keywordInTitle,
  keywordInMeta,
  keywordInH1
].filter(Boolean).length;

// =======================
// 4. SEO RULES
// =======================

// Title length (ideal: 50–60)
const titleLength = title.length;
const titleGood = titleLength >= 50 && titleLength <= 60;

// Meta length (ideal: 120–160)
const metaLength = meta.length;
const metaGood = metaLength >= 120 && metaLength <= 160;

// Content quality
const thinContent = contentLength < 800;

// Link issues
const tooManyExternalLinks = externalLinks.length > 50;
const lowInternalLinks = internalLinks.length < 5;

// =======================
// 5. PENALTY-BASED SCORING
// =======================
let score = 100;

// Missing basics
if (!title) score -= 15;
if (!meta) score -= 15;
if (!h1) score -= 10;

// Optimization issues
if (!titleGood) score -= 10;
if (!metaGood) score -= 10;

// Keyword usage
if (keywordScore === 0) score -= 20;
if (keywordScore === 1) score -= 10;

// Content
if (thinContent) score -= 15;

// Links
if (tooManyExternalLinks) score -= 15;
if (lowInternalLinks) score -= 10;

// Prevent negative score
if (score < 0) score = 0;

// =======================
// 6. RECOMMENDATIONS
// =======================
const recommendations = [];

if (!title) {
  recommendations.push("Add a title tag");
} else if (!titleGood) {
  recommendations.push("Optimize title length (50–60 characters)");
}

if (!meta) {
  recommendations.push("Add a meta description");
} else if (!metaGood) {
  recommendations.push("Optimize meta description (120–160 characters)");
}

if (!h1) {
  recommendations.push("Add an H1 tag");
}

if (keywordScore < 2) {
  recommendations.push("Improve keyword placement in title, meta, and H1");
}

if (thinContent) {
  recommendations.push("Increase content length (minimum 800+ words)");
}

if (tooManyExternalLinks) {
  recommendations.push("Reduce excessive external links");
}

if (lowInternalLinks) {
  recommendations.push("Add more internal links");
}

// =======================
// 7. FINAL OUTPUT
// =======================
return [{
  url: $json.url,

  // Basic checks
  missing_title: title.length === 0,
  missing_meta: meta.length === 0,
  missing_h1: h1.length === 0,

  // Lengths
  title_length: titleLength,
  meta_length: metaLength,

  // Content
  thin_content: thinContent,

  // Keyword
  keyword_score: keywordScore,

  // Links
  total_links: links.length,
  internal_links: internalLinks.length,
  external_links: externalLinks.length,
  anchor_links: anchorLinks.length,

  // Issues
  issues: {
    title_length_issue: !titleGood,
    meta_length_issue: !metaGood,
    too_many_external_links: tooManyExternalLinks,
    low_internal_links: lowInternalLinks
  },

  // Final score
  seo_score: score,

  // Actionable insights
  recommendations
}];

